import { cn } from "@/lib/utils";
import { CSSProperties } from "react";

interface OpenerProps {
	/**
	 * Set the background image for the opener
	 */
	src: string;
	/**
	 * Set the copyright for the opener image
	 */
	copyright: string;
	/**
	 * Set the title for the opener
	 */
	title: string;
	/**
	 * Set the description for the opener
	 */
	description: string;
	/**
	 * Set the height for the opener
	 */
	height?: number;
	/**
	 * Set the height for the opener
	 */
	className?: string;
}

export function Opener({
	src,
	copyright,
	title,
	description,
	height = 500,
	className,
}: OpenerProps) {
	return (
		<div
			className="relative pb-[var(--height)]"
			style={{ "--height": `${height}px` } as CSSProperties}
		>
			<div
				className={cn(
					"absolute h-[var(--height)] w-screen bg-grey-darkest",
					className,
				)}
			>
				<div
					className="flex h-[var(--height)] max-h-[70vh] w-full overflow-hidden [background-image:var(--src)] bg-cover bg-center"
					style={{ "--src": `url(${src})` } as CSSProperties}
				/>
				{copyright && (
					<p className="absolute bottom-1 left-1 text-sm text-white lg:left-3">
						{copyright}
					</p>
				)}
				<div className="absolute inset-0 flex items-center justify-center px-4">
					<div className="max-w-[61.25rem] bg-white px-8 py-10 text-center">
						<h1 className="mb-2 font-bold">{title}</h1>
						<p>{description}</p>
					</div>
				</div>
			</div>
		</div>
	);
}
